## 2.  C++ stubs – `blocksci_stubs.cpp`

> **Important:**  The file must be compiled with a C++ compiler (g++, clang++) and
> linked against the BlockSci library (`-lblocksci`).  The OCaml runtime
> headers are C‑only, so we wrap everything in `extern "C"` where required.

```cpp
/* blocksci_stubs.cpp – OCaml <-> BlockSci bridge
 *
 * Compile (example):
 *   ocamlopt -c blocksci.mli
 *   ocamlopt -ccopt "-I/usr/include/ocaml" -c blocksci_stubs.cpp
 *   ocamlopt -o blocksci.cmxa blocksci.cmx blocksci_stubs.o -cclib -lblocksci
 *
 * Adjust the include path / library name to match your BlockSci installation.
 */

#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/bigarray.h>

#include <string>

// ----------------------------------------------------------------------
// 1.  Include the (hypothetical) BlockSci C++ headers.
// ----------------------------------------------------------------------
/* -------------------------------------------------------------
   The real BlockSci library ships a header (e.g. blocksci.hpp)
   that defines the following classes.  The signatures below are
   a minimal subset that we need for the binding.  Replace them
   with the real ones when you integrate the code.
   ------------------------------------------------------------- */
class Block {
public:
    std::string hash() const;
    int          height() const;
    double       timestamp() const;
};

class BlockIterator {
public:
    BlockIterator(const BlockIterator&) = delete;
    BlockIterator& operator=(const BlockIterator&) = delete;
    BlockIterator(BlockIterator&&) noexcept = default;
    BlockIterator& operator=(BlockIterator&&) noexcept = default;

    bool   has_next() const;
    Block  next();                 // returns a copy of the next block
};

class BlockChain {
public:
    explicit BlockChain(const std::string& path);
    ~BlockChain();

    BlockIterator begin() const;   // iterator over the whole chain
};

/* -------------------------------------------------------------
   End of fake declarations – replace with the real ones.
   ------------------------------------------------------------- */

// ----------------------------------------------------------------------
// 2.  Helper macros to extract the raw pointers stored inside OCaml custom values
// ----------------------------------------------------------------------
#define Collection_val(v) (*((BlockChain **) Data_custom_val(v)))
#define Block_ptr_val(v) (*((Block **) Data_custom_val(v)))

// ----------------------------------------------------------------------
// 3.  Custom operations for the opaque types
// ----------------------------------------------------------------------

// ----- collection ----------------------------------------------------
static void collection_finalize(value v) {
    BlockChain * * p = (BlockChain **) Data_custom_val(v);
    if (*p != nullptr) {
        delete *p;
        *p = nullptr;
    }
}
static int collection_compare(value v1, value v2) {
    // Collections are compared by pointer value – sufficient for OCaml.
    return (int)(intptr_t)Collection_val(v1) - (int)(intptr_t)Collection_val(v2);
}
static intnat collection_hash(value v) {
    return (intnat)(intptr_t)Collection_val(v);
}
static struct custom_operations collection_ops = {
    "Blocksci.collection",
    collection_finalize,
    collection_compare,
    collection_hash,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

// ----- block ---------------------------------------------------------
static void block_finalize(value v) {
    Block ** p = (Block **) Data_custom_val(v);
    if (*p != nullptr) {
        delete *p;
        *p = nullptr;
    }
}
static struct custom_operations block_ops = {
    "Blocksci.block",
    block_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

// ----------------------------------------------------------------------
// 4.  OCaml‑visible primitives
// ----------------------------------------------------------------------

// ----------------------------------------------------------------------
// 4.1  Open a collection
// ----------------------------------------------------------------------
extern "C" CAMLprim value caml_blocksci_open_collection(value v_path) {
    CAMLparam1(v_path);
    CAMLlocal1(v_res);

    const char *c_path = String_val(v_path);
    BlockChain *chain = nullptr;
    try {
        chain = new BlockChain(std::string(c_path));
    } catch (const std::exception &e) {
        caml_failwith(e.what());
    } catch (...) {
        caml_failwith("BlockSci: unknown error while opening collection");
    }

    v_res = caml_alloc_custom(&collection_ops, sizeof(BlockChain *), 0, 1);
    Collection_val(v_res) = chain;
    CAMLreturn(v_res);
}

// ----------------------------------------------------------------------
// 4.2  Close a collection (optional – also done automatically by GC)
// ----------------------------------------------------------------------
extern "C" CAMLprim value caml_blocksci_close_collection(value v_coll) {
    CAMLparam1(v_coll);
    BlockChain * * p = (BlockChain **) Data_custom_val(v_coll);
    if (*p != nullptr) {
        delete *p;
        *p = nullptr;
    }
    CAMLreturn(Val_unit);
}

// ----------------------------------------------------------------------
// 4.3  Accessors for a block
// ----------------------------------------------------------------------
extern "C" CAMLprim value caml_blocksci_block_hash(value v_blk) {
    CAMLparam1(v_blk);
    Block *blk = Block_ptr_val(v_blk);
    // BlockSci returns a hex string; OCaml wants a normal string.
    std::string h = blk->hash();
    CAMLreturn(caml_copy_string(h.c_str()));
}

extern "C" CAMLprim value caml_blocksci_block_height(value v_blk) {
    CAMLparam1(v_blk);
    Block *blk = Block_ptr_val(v_blk);
    CAMLreturn(Val_int(blk->height()));
}

extern "C" CAMLprim value caml_blocksci_block_timestamp(value v_blk) {
    CAMLparam1(v_blk);
    Block *blk = Block_ptr_val(v_blk);
    CAMLreturn(caml_copy_double(blk->timestamp()));
}

// ----------------------------------------------------------------------
// 4.4  Iterate over all blocks, invoking a user supplied OCaml callback
// ----------------------------------------------------------------------
extern "C" CAMLprim value caml_blocksci_iter_blocks(value v_coll, value v_cb) {
    CAMLparam2(v_coll, v_cb);
    CAMLlocal1(v_blk);

    BlockChain *chain = Collection_val(v_coll);
    if (chain == nullptr) caml_failwith("BlockSci: collection is already closed");

    // Obtain an iterator that walks the whole chain.
    BlockIterator it = chain->begin();

    while (it.has_next()) {
        // 1) Grab the next Block (by value) and wrap it in an OCaml custom.
        Block *blk = nullptr;
        try {
            blk = new Block(it.next());   // copy-construct a fresh Block
        } catch (const std::exception &e) {
            caml_failwith(e.what());
        } catch (...) {
            caml_failwith("BlockSci: unexpected error while iterating");
        }

        // 2) Build the OCaml value that represents this block.
        v_blk = caml_alloc_custom(&block_ops, sizeof(Block *), 0, 1);
        Block_ptr_val(v_blk) = blk;   // ownership transferred to OCaml value

        // 3) Call the user callback.  Use the *_exn version so we can
        //    detect exceptions and stop the iteration cleanly.
        value cb_res = caml_callback_exn(v_cb, v_blk);
        if (Is_exception_result(cb_res)) {
            // The user raised an exception → propagate it outward.
            // First, free the iterator (no more blocks will be visited).
            // The block value we just created will be finalized by the
            // GC when the exception propagates, so we do not delete it
            // ourselves.
            caml_raise(cb_res);
        }

        // 4) The callback succeeded; we can now free the Block because the
        //    OCaml value is no longer needed.  The custom finalizer will run
        //    shortly after we exit the allocation region.
        //    (We *could* keep the block alive for the whole walk, but that
        //    would keep the whole chain in memory; freeing it eagerly is
        //    cheaper and matches the semantics of most iterator bindings.)
    }

    CAMLreturn(Val_unit);
}
```

