## 3.  How to compile & link

```bash
# 1) Compile the interface
ocamlopt -c blocksci.mli

# 2) Compile the C++ stub (adjust include path to your OCaml installation)
ocamlopt -ccopt "-I$(ocamlc -where)" -c blocksci_stubs.cpp

# 3) Build the library (replace -lblocksci with the real name)
ocamlopt -a -o blocksci.cmxa blocksci.cmx blocksci_stubs.o -cclib -lblocksci

# 4) Use it from OCaml
#    (example program below)
```

### Minimal OCaml test program

```ocaml
(* test_blocksci.ml *)
let () =
  let coll = Blocksci.open_collection "/path/to/blocksci/index" in
  Blocksci.iter_blocks coll (fun blk ->
    Printf.printf "height=%d hash=%s ts=%f\n"
      (Blocksci.block_height blk)
      (Blocksci.block_hash blk)
      (Blocksci.block_timestamp blk)
  );
  Blocksci.close_collection coll
```

Compile:

```bash
ocamlopt -o test_blocksci unix.cmxa blocksci.cmxa test_blocksci.ml
```

Run it; you should see one line per block of the blockchain.

